const REQUIRED_STRIPE_ENV_KEYS = [
  "STRIPE_SECRET_KEY",
  "NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY",
  "STRIPE_WEBHOOK_SECRET",
  "APP_URL",
] as const;

export type StripeEnvKey = (typeof REQUIRED_STRIPE_ENV_KEYS)[number];

export type StripeConfigMode = "missing" | "misconfigured" | "configured";

export interface StripeConfigStatus {
  mode: StripeConfigMode;
  missingKeys: StripeEnvKey[];
}

export interface StripeConfig {
  secretKey: string;
  publishableKey: string;
  webhookSecret: string;
  appUrl: string;
}

export class StripeNotConfiguredError extends Error {
  readonly code = "stripe_not_configured" as const;

  constructor() {
    super("Stripe is not configured. Set STRIPE_SECRET_KEY to enable billing.");
    this.name = "StripeNotConfiguredError";
  }
}

export class StripeMisconfiguredError extends Error {
  readonly code = "stripe_misconfigured" as const;
  readonly missingKeys: StripeEnvKey[];

  constructor(missingKeys: StripeEnvKey[]) {
    super(
      `Stripe is partially configured. Missing required env var(s): ${missingKeys.join(", ")}. ` +
        "Set all of STRIPE_SECRET_KEY, NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY, STRIPE_WEBHOOK_SECRET, and APP_URL, or set none of them.",
    );
    this.name = "StripeMisconfiguredError";
    this.missingKeys = missingKeys;
  }
}

function readStripeEnv(): Record<StripeEnvKey, string | undefined> {
  return {
    STRIPE_SECRET_KEY: process.env.STRIPE_SECRET_KEY,
    NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY: process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY,
    STRIPE_WEBHOOK_SECRET: process.env.STRIPE_WEBHOOK_SECRET,
    APP_URL: process.env.APP_URL,
  };
}

// Missing = no STRIPE_SECRET_KEY (soft-fail). Secret present implies all
// other required vars must also be set or we treat it as misconfigured.
export function getStripeConfigStatus(): StripeConfigStatus {
  const env = readStripeEnv();

  if (!env.STRIPE_SECRET_KEY) {
    return {
      mode: "missing",
      missingKeys: REQUIRED_STRIPE_ENV_KEYS.filter((key) => !env[key]),
    };
  }

  const missingKeys = REQUIRED_STRIPE_ENV_KEYS.filter((key) => !env[key]);
  if (missingKeys.length > 0) {
    return { mode: "misconfigured", missingKeys };
  }

  return { mode: "configured", missingKeys: [] };
}

export function isStripeConfigured(): boolean {
  return getStripeConfigStatus().mode === "configured";
}

export function getStripeConfig(): StripeConfig {
  const status = getStripeConfigStatus();

  if (status.mode === "missing") {
    throw new StripeNotConfiguredError();
  }

  if (status.mode === "misconfigured") {
    throw new StripeMisconfiguredError(status.missingKeys);
  }

  const env = readStripeEnv();
  return {
    secretKey: env.STRIPE_SECRET_KEY as string,
    publishableKey: env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY as string,
    webhookSecret: env.STRIPE_WEBHOOK_SECRET as string,
    appUrl: env.APP_URL as string,
  };
}

import Stripe from "stripe";
import { getStripeConfig } from "./env";

let cachedClient: Stripe | null = null;
let cachedSecretKey: string | null = null;

// Mirrors the caching pattern in src/lib/postmark/client.ts. getStripeConfig()
// throws StripeNotConfiguredError or StripeMisconfiguredError with a clear
// message when Stripe isn't ready — let that propagate to the caller's error
// handling (API routes map it to a 503/500 JSON response) instead of catching
// it here.
export function getStripe(): Stripe {
  const config = getStripeConfig();

  if (!cachedClient || cachedSecretKey !== config.secretKey) {
    cachedClient = new Stripe(config.secretKey);
    cachedSecretKey = config.secretKey;
  }

  return cachedClient;
}

export type PlanKey = "basic" | "pro" | "team";

export interface PlanDefinition {
  key: PlanKey;
  name: string;
  description: string;
  features: readonly string[];
}

// Price IDs live in env only — never hardcode a Stripe price ID in JSX or in
// this list. `getPlanPriceId` is the single place that reads them.
const PLAN_PRICE_ENV_KEYS: Record<PlanKey, string> = {
  basic: "STRIPE_PRICE_ID_BASIC",
  pro: "STRIPE_PRICE_ID_PRO",
  team: "STRIPE_PRICE_ID_TEAM",
};

const PLAN_DEFINITIONS: readonly PlanDefinition[] = [
  {
    key: "basic",
    name: "Basic",
    description: "For solo builders getting started.",
    features: ["1 project", "Community support", "Core features"],
  },
  {
    key: "pro",
    name: "Pro",
    description: "For growing teams that need more room.",
    features: ["Unlimited projects", "Priority support", "Advanced features"],
  },
  {
    key: "team",
    name: "Team",
    description: "For teams that need to collaborate at scale.",
    features: ["Everything in Pro", "Team seats", "Dedicated support"],
  },
];

const PLAN_KEYS: ReadonlySet<string> = new Set(PLAN_DEFINITIONS.map((plan) => plan.key));

export function listPlans(): readonly PlanDefinition[] {
  return PLAN_DEFINITIONS;
}

export function getPlanDefinition(planKey: PlanKey): PlanDefinition {
  const plan = PLAN_DEFINITIONS.find((definition) => definition.key === planKey);
  if (!plan) {
    throw new Error(`Unknown plan key "${planKey}".`);
  }
  return plan;
}

export function isPlanKey(value: string): value is PlanKey {
  return PLAN_KEYS.has(value);
}

export class PlanPriceNotConfiguredError extends Error {
  readonly code = "plan_price_not_configured" as const;
  readonly planKey: PlanKey;

  constructor(planKey: PlanKey) {
    super(
      `Missing ${PLAN_PRICE_ENV_KEYS[planKey]} for plan "${planKey}". Set it in your environment to enable checkout for this plan.`,
    );
    this.name = "PlanPriceNotConfiguredError";
    this.planKey = planKey;
  }
}

export function getPlanPriceId(planKey: PlanKey): string {
  const priceId = process.env[PLAN_PRICE_ENV_KEYS[planKey]];
  if (!priceId) {
    throw new PlanPriceNotConfiguredError(planKey);
  }
  return priceId;
}

export function isPlanPriceConfigured(planKey: PlanKey): boolean {
  return Boolean(process.env[PLAN_PRICE_ENV_KEYS[planKey]]);
}

export function getPlanKeyForPriceId(priceId: string): PlanKey | null {
  for (const planKey of Object.keys(PLAN_PRICE_ENV_KEYS) as PlanKey[]) {
    if (process.env[PLAN_PRICE_ENV_KEYS[planKey]] === priceId) {
      return planKey;
    }
  }
  return null;
}

import { createAdminClient } from "@/lib/supabase/admin";

export type SubscriptionStatus =
  | "active"
  | "trialing"
  | "past_due"
  | "canceled"
  | "unpaid"
  | "incomplete"
  | "incomplete_expired"
  | "paused";

export interface Subscription {
  id: string;
  userId: string;
  stripeCustomerId: string;
  stripeSubscriptionId: string;
  planKey: string;
  status: SubscriptionStatus;
  cancelAtPeriodEnd: boolean;
  currentPeriodEnd: string | null;
}

interface SubscriptionRow {
  id: string;
  user_id: string;
  stripe_customer_id: string;
  stripe_subscription_id: string;
  plan_key: string;
  status: string;
  cancel_at_period_end: boolean;
  current_period_end: string | null;
}

const ACTIVE_SUBSCRIPTION_STATUSES: ReadonlySet<string> = new Set(["active", "trialing"]);

// Block a second Checkout while these open statuses still exist.
const CHECKOUT_BLOCKING_SUBSCRIPTION_STATUSES: ReadonlySet<string> = new Set([
  "active",
  "trialing",
  "past_due",
  "unpaid",
  "incomplete",
  "paused",
]);

function mapSubscriptionRow(row: SubscriptionRow): Subscription {
  return {
    id: row.id,
    userId: row.user_id,
    stripeCustomerId: row.stripe_customer_id,
    stripeSubscriptionId: row.stripe_subscription_id,
    planKey: row.plan_key,
    status: row.status as SubscriptionStatus,
    cancelAtPeriodEnd: row.cancel_at_period_end,
    currentPeriodEnd: row.current_period_end,
  };
}

function pickCurrentSubscription(rows: SubscriptionRow[]): SubscriptionRow | null {
  if (rows.length === 0) {
    return null;
  }

  const active = rows.filter((row) => ACTIVE_SUBSCRIPTION_STATUSES.has(row.status));
  const candidates = active.length > 0 ? active : rows;

  return [...candidates].sort((left, right) => {
    const leftEnd = left.current_period_end ? Date.parse(left.current_period_end) : 0;
    const rightEnd = right.current_period_end ? Date.parse(right.current_period_end) : 0;
    return rightEnd - leftEnd;
  })[0];
}

// Admin client (RLS on, no policies). Caller must authenticate userId first.
// Prefer active/trialing among multiple subscription rows per user.
export async function getSubscription(userId: string): Promise<Subscription | null> {
  const supabase = createAdminClient();
  const { data, error } = await supabase.from("subscriptions").select("*").eq("user_id", userId);

  if (error) {
    throw error;
  }

  const row = pickCurrentSubscription((data ?? []) as SubscriptionRow[]);
  return row ? mapSubscriptionRow(row) : null;
}

export async function hasActiveSubscription(userId: string): Promise<boolean> {
  const subscription = await getSubscription(userId);
  return subscription !== null && ACTIVE_SUBSCRIPTION_STATUSES.has(subscription.status);
}

export async function hasCheckoutBlockingSubscription(userId: string): Promise<boolean> {
  const supabase = createAdminClient();
  const { data, error } = await supabase.from("subscriptions").select("status").eq("user_id", userId);

  if (error) {
    throw error;
  }

  return ((data ?? []) as Array<{ status: string }>).some((row) =>
    CHECKOUT_BLOCKING_SUBSCRIPTION_STATUSES.has(row.status),
  );
}

import { NextResponse } from "next/server";
import { StripeMisconfiguredError, StripeNotConfiguredError } from "./env";
import { PlanPriceNotConfiguredError } from "./plans";

// Map typed billing errors to { error, code }; null means rethrow.
export function stripeBillingErrorResponse(error: unknown): NextResponse | null {
  if (error instanceof StripeNotConfiguredError) {
    return NextResponse.json({ error: error.message, code: error.code }, { status: 503 });
  }

  if (error instanceof StripeMisconfiguredError) {
    return NextResponse.json({ error: error.message, code: error.code }, { status: 500 });
  }

  if (error instanceof PlanPriceNotConfiguredError) {
    return NextResponse.json({ error: error.message, code: error.code }, { status: 503 });
  }

  return null;
}

import type Stripe from "stripe";
import { createAdminClient } from "@/lib/supabase/admin";
import { getPlanKeyForPriceId } from "./plans";

type SupabaseAdminClient = ReturnType<typeof createAdminClient>;

type WebhookEventStatus = "processed" | "failed";

// Idempotent: skip already-processed event ids. Writes use createAdminClient()
// (RLS enabled, no policies on billing tables).
export async function handleEvent(event: Stripe.Event): Promise<void> {
  const supabase = createAdminClient();

  const { data: existingEvent } = await supabase
    .from("stripe_webhook_events")
    .select("status")
    .eq("id", event.id)
    .maybeSingle();

  if (existingEvent?.status === "processed") {
    return;
  }

  try {
    await routeEvent(supabase, event);
    await recordWebhookEvent(supabase, event, "processed", null);
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown webhook handling error.";
    await recordWebhookEvent(supabase, event, "failed", message);
    throw error;
  }
}

async function routeEvent(supabase: SupabaseAdminClient, event: Stripe.Event): Promise<void> {
  switch (event.type) {
    case "checkout.session.completed":
      await handleCheckoutSessionCompleted(supabase, event.data.object as Stripe.Checkout.Session);
      return;
    case "customer.subscription.created":
    case "customer.subscription.updated":
      await upsertSubscription(
        supabase,
        event.data.object as Stripe.Subscription,
        event.created,
      );
      return;
    case "customer.subscription.deleted":
      await markSubscriptionCanceled(
        supabase,
        event.data.object as Stripe.Subscription,
        event.created,
      );
      return;
    case "invoice.paid":
    case "invoice.payment_failed":
      await handleInvoiceEvent(supabase, event.data.object as Stripe.Invoice, event.created);
      return;
    default:
      // Unhandled event types are still recorded.
      return;
  }
}

async function handleCheckoutSessionCompleted(
  supabase: SupabaseAdminClient,
  session: Stripe.Checkout.Session,
): Promise<void> {
  const userId = session.client_reference_id ?? session.metadata?.user_id;
  const customerId = typeof session.customer === "string" ? session.customer : session.customer?.id;

  if (!userId || !customerId) {
    return;
  }

  const { error } = await supabase.from("billing_customers").upsert(
    {
      user_id: userId,
      stripe_customer_id: customerId,
      email: session.customer_details?.email ?? session.customer_email ?? null,
    },
    { onConflict: "user_id" },
  );

  if (error) {
    throw error;
  }
}

// basil+: current_period_end lives on SubscriptionItem, not Subscription.
function getSubscriptionPeriodEnd(subscription: Stripe.Subscription): string | null {
  const item = subscription.items.data[0];
  if (!item || typeof item.current_period_end !== "number") {
    return null;
  }
  return new Date(item.current_period_end * 1000).toISOString();
}

async function resolveUserIdForCustomer(
  supabase: SupabaseAdminClient,
  customerId: string,
): Promise<string | null> {
  const { data } = await supabase
    .from("billing_customers")
    .select("user_id")
    .eq("stripe_customer_id", customerId)
    .maybeSingle();

  return data?.user_id ?? null;
}

async function shouldSkipStaleSubscriptionEvent(
  supabase: SupabaseAdminClient,
  stripeSubscriptionId: string,
  eventCreated: number,
): Promise<boolean> {
  const { data } = await supabase
    .from("subscriptions")
    .select("stripe_event_created")
    .eq("stripe_subscription_id", stripeSubscriptionId)
    .maybeSingle();

  return (
    typeof data?.stripe_event_created === "number" && data.stripe_event_created > eventCreated
  );
}

async function upsertSubscription(
  supabase: SupabaseAdminClient,
  subscription: Stripe.Subscription,
  eventCreated: number,
): Promise<void> {
  if (await shouldSkipStaleSubscriptionEvent(supabase, subscription.id, eventCreated)) {
    return;
  }

  const customerId =
    typeof subscription.customer === "string" ? subscription.customer : subscription.customer.id;

  // Prefer subscription metadata.user_id; fall back to billing_customers.
  const userId = subscription.metadata?.user_id || (await resolveUserIdForCustomer(supabase, customerId));

  if (!userId) {
    throw new Error(
      `Cannot upsert subscription ${subscription.id}: no user_id in metadata and no billing_customers row for customer ${customerId}.`,
    );
  }

  const priceId = subscription.items.data[0]?.price.id;
  // Live price mapping wins over potentially stale metadata.plan_key.
  const planKey =
    (priceId ? getPlanKeyForPriceId(priceId) : null) ||
    subscription.metadata?.plan_key ||
    priceId ||
    "unknown";

  // Key by stripe_subscription_id; entitlements pick the current row.
  const { error } = await supabase.from("subscriptions").upsert(
    {
      user_id: userId,
      stripe_customer_id: customerId,
      stripe_subscription_id: subscription.id,
      plan_key: planKey,
      status: subscription.status,
      cancel_at_period_end: subscription.cancel_at_period_end,
      current_period_end: getSubscriptionPeriodEnd(subscription),
      stripe_event_created: eventCreated,
      updated_at: new Date().toISOString(),
    },
    { onConflict: "stripe_subscription_id" },
  );

  if (error) {
    throw error;
  }

  // Keep billing_customers in sync so portal works even if
  // checkout.session.completed arrives late or is missed.
  const { error: customerError } = await supabase.from("billing_customers").upsert(
    {
      user_id: userId,
      stripe_customer_id: customerId,
    },
    { onConflict: "user_id" },
  );

  if (customerError) {
    throw customerError;
  }
}

async function markSubscriptionCanceled(
  supabase: SupabaseAdminClient,
  subscription: Stripe.Subscription,
  eventCreated: number,
): Promise<void> {
  // Tombstone via upsert so out-of-order deleted-before-created still sticks.
  await upsertSubscription(
    supabase,
    { ...subscription, status: "canceled" },
    eventCreated,
  );
}

function getInvoiceSubscriptionReference(
  invoice: Stripe.Invoice,
): string | Stripe.Subscription | null {
  // Legacy Invoice.subscription (pre-basil).
  if ("subscription" in invoice) {
    const legacy = (
      invoice as Stripe.Invoice & { subscription?: string | Stripe.Subscription | null }
    ).subscription;
    if (typeof legacy === "string" || (legacy && typeof legacy === "object")) {
      return legacy;
    }
  }

  // basil+: invoice.parent.subscription_details.subscription.
  const parent = (
    invoice as Stripe.Invoice & {
      parent?: {
        type?: string | null;
        subscription_details?: {
          subscription?: string | Stripe.Subscription | null;
        } | null;
      } | null;
    }
  ).parent;

  const fromParent = parent?.subscription_details?.subscription;
  if (typeof fromParent === "string" || (fromParent && typeof fromParent === "object")) {
    return fromParent;
  }

  return null;
}

async function handleInvoiceEvent(
  supabase: SupabaseAdminClient,
  invoice: Stripe.Invoice,
  eventCreated: number,
): Promise<void> {
  // Keep local status in sync when subscription.* events are missing.
  const rawSubscription = getInvoiceSubscriptionReference(invoice);
  const subscriptionId =
    typeof rawSubscription === "string" ? rawSubscription : rawSubscription?.id;

  if (!subscriptionId) {
    return;
  }

  if (typeof rawSubscription === "object" && rawSubscription !== null) {
    await upsertSubscription(supabase, rawSubscription, eventCreated);
    return;
  }

  if (await shouldSkipStaleSubscriptionEvent(supabase, subscriptionId, eventCreated)) {
    return;
  }

  // Do not revive canceled/incomplete_expired from bare invoice updates.
  const { data: existing } = await supabase
    .from("subscriptions")
    .select("status")
    .eq("stripe_subscription_id", subscriptionId)
    .maybeSingle();

  if (
    existing?.status === "canceled" ||
    existing?.status === "incomplete_expired"
  ) {
    return;
  }

  const status = invoice.status === "paid" ? "active" : "past_due";
  const { error } = await supabase
    .from("subscriptions")
    .update({
      status,
      stripe_event_created: eventCreated,
      updated_at: new Date().toISOString(),
    })
    .eq("stripe_subscription_id", subscriptionId);

  if (error) {
    throw error;
  }
}

async function recordWebhookEvent(
  supabase: SupabaseAdminClient,
  event: Stripe.Event,
  status: WebhookEventStatus,
  error: string | null,
): Promise<void> {
  const { error: writeError } = await supabase.from("stripe_webhook_events").upsert({
    id: event.id,
    type: event.type,
    status,
    payload: event,
    processed_at: status === "processed" ? new Date().toISOString() : null,
    error,
  });

  if (writeError) {
    throw writeError;
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { getStripe } from "@/lib/stripe/client";
import { hasCheckoutBlockingSubscription } from "@/lib/stripe/entitlements";
import { getStripeConfig } from "@/lib/stripe/env";
import { stripeBillingErrorResponse } from "@/lib/stripe/http";
import { getPlanPriceId, isPlanKey } from "@/lib/stripe/plans";

const OPEN = new Set(["active", "trialing", "past_due", "unpaid", "incomplete", "paused"]);

function alreadyOpen() {
  return NextResponse.json(
    {
      error:
        "You already have an open subscription. Use the billing portal to update payment or change plans.",
      code: "subscription_already_active",
    },
    { status: 409 },
  );
}

export async function POST(request: Request) {
  let body: { planKey?: unknown };
  try {
    body = (await request.json()) as { planKey?: unknown };
  } catch {
    return NextResponse.json({ error: "Invalid JSON body." }, { status: 400 });
  }
  if (typeof body.planKey !== "string" || !isPlanKey(body.planKey)) {
    return NextResponse.json(
      { error: 'planKey must be one of "basic", "pro", or "team".' },
      { status: 400 },
    );
  }

  const supabase = await createClient();
  const { data: userData, error: userError } = await supabase.auth.getUser();
  if (userError || !userData.user) {
    return NextResponse.json({ error: "Authentication required." }, { status: 401 });
  }
  const user = userData.user;

  let config: ReturnType<typeof getStripeConfig>;
  let priceId: string;
  try {
    config = getStripeConfig();
    priceId = getPlanPriceId(body.planKey);
  } catch (error) {
    const response = stripeBillingErrorResponse(error);
    if (response) return response;
    throw error;
  }

  if (await hasCheckoutBlockingSubscription(user.id)) return alreadyOpen();

  const stripe = getStripe();
  const admin = createAdminClient();
  // Only reuse a customer ID we persisted for this user — never look up by email.
  const { data: mapped } = await admin
    .from("billing_customers")
    .select("stripe_customer_id")
    .eq("user_id", user.id)
    .maybeSingle();
  const customerId = mapped?.stripe_customer_id as string | undefined;
  if (customerId) {
    const subs = await stripe.subscriptions.list({
      customer: customerId,
      status: "all",
      limit: 100,
    });
    if (subs.data.some((s) => OPEN.has(s.status))) return alreadyOpen();
  }

  const session = await stripe.checkout.sessions.create({
    mode: "subscription",
    customer: customerId,
    customer_email: customerId ? undefined : (user.email ?? undefined),
    client_reference_id: user.id,
    line_items: [{ price: priceId, quantity: 1 }],
    subscription_data: { metadata: { user_id: user.id, plan_key: body.planKey } },
    success_url: `${config.appUrl}/settings/billing?checkout=success`,
    cancel_url: `${config.appUrl}/pricing?checkout=cancelled`,
  });
  if (!session.url) {
    return NextResponse.json({ error: "Stripe did not return a checkout URL." }, { status: 500 });
  }
  return NextResponse.json({ url: session.url });
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";
import { getStripe } from "@/lib/stripe/client";
import { getStripeConfig } from "@/lib/stripe/env";
import { stripeBillingErrorResponse } from "@/lib/stripe/http";

export async function POST() {
  const supabase = await createClient();
  const { data: userData, error: userError } = await supabase.auth.getUser();
  if (userError || !userData.user) {
    return NextResponse.json({ error: "Authentication required." }, { status: 401 });
  }

  let config: ReturnType<typeof getStripeConfig>;
  try {
    config = getStripeConfig();
  } catch (error) {
    const response = stripeBillingErrorResponse(error);
    if (response) {
      return response;
    }
    throw error;
  }

  const adminClient = createAdminClient();
  const { data: billingCustomer } = await adminClient
    .from("billing_customers")
    .select("stripe_customer_id")
    .eq("user_id", userData.user.id)
    .maybeSingle();

  let stripeCustomerId = billingCustomer?.stripe_customer_id;
  if (!stripeCustomerId) {
    const { data: subscription } = await adminClient
      .from("subscriptions")
      .select("stripe_customer_id")
      .eq("user_id", userData.user.id)
      .limit(1)
      .maybeSingle();
    stripeCustomerId = subscription?.stripe_customer_id;
  }

  if (!stripeCustomerId) {
    return NextResponse.json(
      {
        error: "No billing account found for this user yet. Start a checkout first.",
        code: "billing_customer_not_found",
      },
      { status: 404 },
    );
  }

  const stripe = getStripe();
  const session = await stripe.billingPortal.sessions.create({
    customer: stripeCustomerId,
    return_url: `${config.appUrl}/settings/billing`,
  });

  return NextResponse.json({ url: session.url });
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { getStripeConfig } from "@/lib/stripe/env";
import { getSubscription } from "@/lib/stripe/entitlements";
import { stripeBillingErrorResponse } from "@/lib/stripe/http";

export async function GET() {
  const supabase = await createClient();
  const { data: userData, error: userError } = await supabase.auth.getUser();
  if (userError || !userData.user) {
    return NextResponse.json({ error: "Authentication required." }, { status: 401 });
  }

  try {
    getStripeConfig();
  } catch (error) {
    const response = stripeBillingErrorResponse(error);
    if (response) {
      return response;
    }
    throw error;
  }

  const subscription = await getSubscription(userData.user.id);
  return NextResponse.json({ subscription });
}

import { NextResponse } from "next/server";
import type Stripe from "stripe";
import { getStripe } from "@/lib/stripe/client";
import { getStripeConfig } from "@/lib/stripe/env";
import { stripeBillingErrorResponse } from "@/lib/stripe/http";
import { handleEvent } from "@/lib/stripe/webhooks";

export async function POST(request: Request) {
  let config: ReturnType<typeof getStripeConfig>;
  try {
    config = getStripeConfig();
  } catch (error) {
    const response = stripeBillingErrorResponse(error);
    if (response) {
      return response;
    }
    throw error;
  }

  const signature = request.headers.get("stripe-signature");
  if (!signature) {
    return NextResponse.json({ error: "Missing Stripe signature header." }, { status: 400 });
  }

  const payload = await request.text();
  const stripe = getStripe();

  let event: Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(payload, signature, config.webhookSecret);
  } catch (error) {
    const message = error instanceof Error ? error.message : "Invalid Stripe webhook signature.";
    return NextResponse.json({ error: message }, { status: 400 });
  }

  try {
    await handleEvent(event);
  } catch (error) {
    console.error("Stripe webhook handling failed", error);
    return NextResponse.json({ error: "Failed to process webhook event." }, { status: 500 });
  }

  return NextResponse.json({ received: true });
}

import type { Metadata } from "next";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
