  const stripeConfigured = isStripeConfigured();
  const plansMissingPrice = plans.filter((plan) => !isPlanPriceConfigured(plan.key));

  return (
    <main className="mx-auto max-w-5xl px-8 py-16">
      <div className="mb-10 text-center">
        <p className="text-[10px] uppercase tracking-[0.28em] text-neutral-500 dark:text-neutral-400">
