      </div>

      {!stripeConfigured ? (
        <Alert className="mb-10">
          <AlertTitle>Stripe is not configured</AlertTitle>
          <AlertDescription>
            Set STRIPE_SECRET_KEY, NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY, STRIPE_WEBHOOK_SECRET, and
            APP_URL (plus STRIPE_PRICE_ID_BASIC / _PRO / _TEAM) to enable checkout. Configure Stripe
            env vars in .env.local — see .env.example.
          </AlertDescription>
        </Alert>
      ) : null}

      {stripeConfigured && plansMissingPrice.length > 0 ? (
        <Alert className="mb-10">
          <AlertTitle>Some plan price IDs are missing</AlertTitle>
          <AlertDescription>
            Set{" "}
            {plansMissingPrice
              .map((plan) => `STRIPE_PRICE_ID_${plan.key.toUpperCase()}`)
              .join(", ")}{" "}
            to enable checkout for those plans. Upgrade stays disabled until each price ID is set.
          </AlertDescription>
        </Alert>
      ) : null}

      <div className="grid gap-6 md:grid-cols-3">
        {plans.map((plan) => {
          const checkoutReady = stripeConfigured && isPlanPriceConfigured(plan.key);
          return (
            <Card key={plan.key}>
              <CardHeader>
                <div className="flex items-center justify-between gap-2">
                  <CardTitle>{plan.name}</CardTitle>
                  {plan.key === FEATURED_PLAN_KEY ? <Badge>Popular</Badge> : null}
                </div>
                <CardDescription>{plan.description}</CardDescription>
              </CardHeader>
              <CardContent>
                <ul className="space-y-2 text-sm text-neutral-600 dark:text-neutral-400">
                  {plan.features.map((feature) => (
                    <li key={feature}>{feature}</li>
                  ))}
                </ul>
              </CardContent>
              <CardFooter>
                <UpgradeButton planKey={plan.key} disabled={!checkoutReady} />
              </CardFooter>
            </Card>
          );
        })}
      </div>
    </main>
  );
}

"use client";

import { Loader2 } from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import type { PlanKey } from "@/lib/stripe/plans";

interface CheckoutResponse {
  url?: string;
  error?: string;
}

interface UpgradeButtonProps {
  planKey: PlanKey;
  disabled?: boolean;
}

export function UpgradeButton({ planKey, disabled }: UpgradeButtonProps) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  async function handleClick() {
    setErrorMessage(null);
    setIsSubmitting(true);

    try {
      const response = await fetch("/api/billing/checkout", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ planKey }),
      });
      const data = (await response.json()) as CheckoutResponse;

      if (!response.ok || !data.url) {
        throw new Error(data.error ?? "Failed to start checkout.");
      }

      window.location.href = data.url;
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : "Failed to start checkout.");
      setIsSubmitting(false);
    }
  }

  return (
    <div className="w-full space-y-2">
      <Button className="w-full" onClick={handleClick} disabled={disabled || isSubmitting}>
        {isSubmitting ? <Loader2 aria-hidden="true" className="h-4 w-4 animate-spin" /> : null}
        <span>Upgrade</span>
      </Button>
      {errorMessage ? <p className="text-xs text-red-600 dark:text-red-300">{errorMessage}</p> : null}
    </div>
  );
}

