import type { Metadata } from "next";
import Link from "next/link";
import { redirect } from "next/navigation";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Badge } from "@/components/ui/badge";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { createAdminClient } from "@/lib/supabase/admin";
import { getSubscription } from "@/lib/stripe/entitlements";
import { getStripeConfigStatus, isStripeConfigured } from "@/lib/stripe/env";
import { getPlanDefinition, isPlanKey } from "@/lib/stripe/plans";
import { createClient } from "@/lib/supabase/server";
import { isSupabaseConfigured } from "@/lib/supabase/server-env";
import { ManageBillingButton } from "./manage-billing-button";

export const metadata: Metadata = { title: "Billing settings" };

export default async function BillingSettingsPage() {
  if (!isSupabaseConfigured()) {
    return (
      <main className="space-y-6">
        <h1 className="text-3xl font-semibold">Billing</h1>
        <Alert>
          <AlertTitle>Supabase is not configured</AlertTitle>
          <AlertDescription>
            Set NEXT_PUBLIC_SUPABASE_URL and NEXT_PUBLIC_SUPABASE_ANON_KEY (see .env.example), then
            sign in to manage billing.
          </AlertDescription>
        </Alert>
      </main>
    );
  }

  const supabase = await createClient();
  const { data: userData } = await supabase.auth.getUser();
  if (!userData.user) {
    redirect("/login?next=/settings/billing");
  }

  const stripeConfigured = isStripeConfigured();
  const stripeStatus = getStripeConfigStatus();
  const subscription = stripeConfigured ? await getSubscription(userData.user.id) : null;
  // Portal accepts customer id from billing_customers or subscriptions.
  let hasBillingCustomer = Boolean(subscription?.stripeCustomerId);
  if (stripeConfigured && !hasBillingCustomer) {
    const adminClient = createAdminClient();
    const { data: billingCustomer } = await adminClient
      .from("billing_customers")
      .select("stripe_customer_id")
      .eq("user_id", userData.user.id)
      .maybeSingle();
    hasBillingCustomer = Boolean(billingCustomer?.stripe_customer_id);
  }
  const planName =
    subscription && isPlanKey(subscription.planKey)
      ? getPlanDefinition(subscription.planKey).name
      : subscription?.planKey;

  return (
    <main className="space-y-6">
      <div>
        <p className="text-[10px] uppercase tracking-[0.28em] text-neutral-500 dark:text-neutral-400">
          Settings
        </p>
        <h1 className="mt-2 text-3xl font-semibold">Billing</h1>
      </div>

      {!stripeConfigured ? (
        <Alert variant={stripeStatus.mode === "misconfigured" ? "destructive" : "default"}>
          <AlertTitle>
            {stripeStatus.mode === "misconfigured"
              ? "Stripe is misconfigured"
              : "Stripe is not configured"}
          </AlertTitle>
          <AlertDescription>
            {stripeStatus.mode === "misconfigured"
              ? `Missing required env var(s): ${stripeStatus.missingKeys.join(", ")}. Set all of STRIPE_SECRET_KEY, NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY, STRIPE_WEBHOOK_SECRET, and APP_URL, or set none of them.`
              : "Set STRIPE_SECRET_KEY, NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY, STRIPE_WEBHOOK_SECRET, and APP_URL to enable billing. See .env.example."}
          </AlertDescription>
        </Alert>
      ) : null}

      <Card>
        <CardHeader>
          <CardTitle>Current plan</CardTitle>
          <CardDescription>Subscription state is updated from Stripe webhooks.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          {subscription ? (
            <>
              <div className="flex items-center gap-2">
                <p className="text-lg font-medium">{planName ?? "Unknown plan"}</p>
                <Badge variant="outline">{subscription.status}</Badge>
              </div>
              {subscription.currentPeriodEnd ? (
                <p className="text-sm text-neutral-600 dark:text-neutral-400">
                  Current period ends{" "}
                  {new Date(subscription.currentPeriodEnd).toLocaleDateString(undefined, {
                    year: "numeric",
                    month: "short",
                    day: "numeric",
                  })}
                  {subscription.cancelAtPeriodEnd ? " (cancels at period end)" : ""}
                </p>
              ) : null}
            </>
          ) : (
            <p className="text-sm text-neutral-600 dark:text-neutral-400">
              No active subscription yet.{" "}
              <Link href="/pricing" className="underline underline-offset-2">
                View pricing
              </Link>
              .
            </p>
          )}
        </CardContent>
        <CardFooter>
          <ManageBillingButton disabled={!stripeConfigured || !hasBillingCustomer} />
        </CardFooter>
      </Card>
    </main>
  );
}

"use client";

import { Loader2 } from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";

interface PortalResponse {
  url?: string;
  error?: string;
}

interface ManageBillingButtonProps {
  disabled?: boolean;
}

export function ManageBillingButton({ disabled }: ManageBillingButtonProps) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  async function handleClick() {
    setErrorMessage(null);
    setIsSubmitting(true);

    try {
      const response = await fetch("/api/billing/portal", { method: "POST" });
      const data = (await response.json()) as PortalResponse;

      if (!response.ok || !data.url) {
        throw new Error(data.error ?? "Failed to open billing portal.");
      }

      window.location.href = data.url;
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : "Failed to open billing portal.");
      setIsSubmitting(false);
    }
  }

  return (
    <div className="space-y-2">
      <Button onClick={handleClick} disabled={disabled || isSubmitting} variant="outline">
        {isSubmitting ? <Loader2 aria-hidden="true" className="h-4 w-4 animate-spin" /> : null}
        <span>Manage billing</span>
      </Button>
      {errorMessage ? <p className="text-xs text-red-600 dark:text-red-300">{errorMessage}</p> : null}
    </div>
  );
}

-- @gic/billing tables. Idempotent. ENABLE RLS only — no CREATE POLICY.
-- subscriptions keyed by stripe_subscription_id; write via service role.

CREATE TABLE IF NOT EXISTS public.billing_customers (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL UNIQUE REFERENCES auth.users (id) ON DELETE CASCADE,
  stripe_customer_id text NOT NULL UNIQUE,
  email text,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.subscriptions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL REFERENCES auth.users (id) ON DELETE CASCADE,
  stripe_customer_id text NOT NULL,
  stripe_subscription_id text NOT NULL UNIQUE,
  plan_key text NOT NULL,
  status text NOT NULL,
  cancel_at_period_end boolean NOT NULL DEFAULT false,
  current_period_end timestamptz,
  stripe_event_created bigint,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

-- Older bake of this migration used UNIQUE(user_id); drop it if present so
-- multiple Stripe subscription ids can coexist for one user.
ALTER TABLE public.subscriptions DROP CONSTRAINT IF EXISTS subscriptions_user_id_key;

ALTER TABLE public.subscriptions
  ADD COLUMN IF NOT EXISTS stripe_event_created bigint;

CREATE TABLE IF NOT EXISTS public.stripe_webhook_events (
  id text PRIMARY KEY,
  type text NOT NULL,
  status text NOT NULL,
  payload jsonb,
  processed_at timestamptz,
  error text,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS billing_customers_stripe_customer_id_idx
  ON public.billing_customers (stripe_customer_id);

CREATE INDEX IF NOT EXISTS subscriptions_user_id_idx
  ON public.subscriptions (user_id);

CREATE INDEX IF NOT EXISTS subscriptions_status_idx
  ON public.subscriptions (status);

ALTER TABLE public.billing_customers ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.subscriptions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.stripe_webhook_events ENABLE ROW LEVEL SECURITY;
